Code.Terraform:
```hcl
# Terraform: enable Bedrock data event logging on an actively logging trail
resource "aws_cloudtrail" "example_resource" {
  name           = "example_resource"
  s3_bucket_name = "example_resource"

  advanced_event_selector {
    name = "Bedrock data events"
    field_selector {
      field  = "eventCategory"
      equals = ["Data"]
    }
    field_selector {
      field  = "resources.type"                # CRITICAL: target Bedrock resources
      equals = ["AWS::Bedrock::Model", "AWS::Bedrock::Guardrail", "AWS::Bedrock::AgentAlias", "AWS::Bedrock::FlowAlias", "AWS::Bedrock::InlineAgent", "AWS::Bedrock::KnowledgeBase", "AWS::Bedrock::Prompt"]
    }
  }
}
```
